    "metrics": {
      "coverage": "missing",
      "gaps": [
        "No request duration histograms per downstream call (CartService→OrderService, CartService→PaymentService, OrderService→InventoryService, PaymentService→Gateway)",
        "No error rate metrics by failure type (timeout, 5xx, circuit breaker open)",
        "No circuit breaker state metrics (open/closed/half-open transitions)",
        "No business metrics (checkout success rate, payment failure rate, inventory reservation failure rate)",
        "No queue depth or concurrent request tracking"
